import { z } from 'zod';
export const loginSchema = z.object({ email: z.string().email(), password: z.string() });
export const updateStatusSchema = z.object({ status: z.enum(['online', 'away', 'offline']) });
export const assignConversationSchema = z.object({ userId: z.string() });
export const updateConversationSchema = z.object({ stage: z.string().optional(), status: z.string().optional(), tags: z.array(z.string()).optional() });
export const sendMessageSchema = z.object({ to: z.string(), text: z.string(), attachments: z.array(z.string()).optional() });
export const noteSchema = z.object({ text: z.string() });
export const taskSchema = z.object({ title: z.string(), description: z.string().optional(), priority: z.string().optional(), dueAt: z.string().optional(), assignedToUserId: z.string().optional() });
export const updateTaskSchema = z.object({ status: z.enum(['open', 'done']) });
export const addTagSchema = z.object({ tagId: z.string() });
export const updateFieldSchema = z.object({ customFieldId: z.string(), value: z.any() });
export const dealSchema = z.object({ contactId: z.string(), pipelineStage: z.string(), value: z.number(), currency: z.string().optional() });
export const updateDealSchema = z.object({ pipelineStage: z.string().optional(), status: z.enum(['open', 'won', 'lost']).optional() });
export const templateSchema = z.object({ name: z.string(), category: z.string(), language: z.string(), body: z.string(), variables: z.any().optional() });
export const broadcastSchema = z.object({ name: z.string(), templateId: z.string(), segment: z.any(), scheduleAt: z.string().optional() });
export const automationSchema = z.object({ name: z.string(), nodes: z.any(), edges: z.any() });
export const settingsSchema = z.object({ businessHours: z.any(), sla: z.any(), notifications: z.any() });
